function monthsOfDance(ingresoDate) {
  if (!ingresoDate) return null;
  const ingreso = new Date(ingresoDate+"T12:00:00");
  const now = new Date();
  return Math.max(0,(now.getFullYear()-ingreso.getFullYear())*12+now.getMonth()-ingreso.getMonth());
}

// ═══════════════════════════════════════════════════════════════
// STYLES
// ═══════════════════════════════════════════════════════════════

const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:ital,wght@0,300;0,400;0,500;1,300&family=DM+Mono:wght@400;500&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#0C0805;--s1:#151008;--s2:#1E160D;--s3:#261C10;
  --border:rgba(255,245,220,0.07);--border2:rgba(255,245,220,0.13);
  --text:#FFF5E6;--muted:rgba(255,245,230,0.38);--muted2:rgba(255,245,230,0.58);
  --fire:#FF4D1C;--gold:#FFB800;
}
html,body{height:100%;background:var(--bg);color:var(--text)}
.app{display:grid;grid-template-columns:220px 1fr;min-height:100vh;font-family:'DM Sans',sans-serif}

/* SIDEBAR */
.sidebar{background:var(--s1);border-right:1px solid var(--border);display:flex;flex-direction:column;padding:28px 0 24px;position:sticky;top:0;height:100vh;overflow:hidden}
.sidebar-logo{padding:0 20px 24px;border-bottom:1px solid var(--border);margin-bottom:12px}
.logo-text{font-family:'Syne',sans-serif;font-size:26px;font-weight:800;letter-spacing:-.5px;line-height:1}
.logo-text span{color:var(--fire)}
.logo-dot{display:inline-block;width:7px;height:7px;background:var(--fire);border-radius:50%;margin-left:2px;margin-bottom:3px;vertical-align:middle}
.logo-sub{font-size:10.5px;color:var(--muted);margin-top:5px;font-family:'DM Mono',monospace;letter-spacing:.04em}
.sidebar-nav{flex:1;padding:4px 10px}
.nav-item{width:100%;display:flex;align-items:center;gap:10px;padding:9px 12px;border-radius:10px;border:none;background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13.5px;font-weight:400;text-align:left;transition:background .15s,color .15s;margin-bottom:2px}
.nav-item:hover{background:var(--s2);color:var(--text)}
.nav-item.active{background:var(--s2);color:var(--text);font-weight:500}
.nav-icon{font-size:15px;width:20px;text-align:center}
.nav-badge{margin-left:auto;font-size:9.5px;font-family:'DM Mono',monospace;background:var(--s3);padding:2px 6px;border-radius:20px;color:var(--muted)}
.sidebar-footer{padding:16px 20px 0;border-top:1px solid var(--border);margin-top:auto}
.month-chip{display:inline-flex;align-items:center;gap:6px;background:rgba(255,184,0,.1);border:1px solid rgba(255,184,0,.2);border-radius:20px;padding:5px 12px;font-size:11px;color:var(--gold);font-family:'DM Mono',monospace}

/* BOTTOM NAV */
.bottom-nav{display:none;position:fixed;bottom:0;left:0;right:0;background:var(--s1);border-top:1px solid var(--border2);padding:8px 4px calc(8px + env(safe-area-inset-bottom));z-index:50}
.bnav-item{flex:1;display:flex;flex-direction:column;align-items:center;gap:3px;padding:4px 2px;border:none;background:transparent;color:var(--muted);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:9.5px;transition:color .15s}
.bnav-item.active{color:var(--fire)}
.bnav-icon{font-size:18px;line-height:1}

/* MAIN */
.main{overflow-y:auto;min-height:100vh;background:var(--bg)}
.section{padding:32px 24px 60px;max-width:960px}
.section-eyebrow{font-family:'DM Mono',monospace;font-size:10px;letter-spacing:.2em;text-transform:uppercase;color:var(--muted);margin-bottom:6px}
.section-title{font-family:'Syne',sans-serif;font-size:26px;font-weight:700;line-height:1.1;margin-bottom:4px}
.section-desc{font-size:13px;color:var(--muted);font-weight:300;margin-bottom:24px}

/* GENRE TABS ROW */
.genre-tabs-row{display:flex;align-items:center;gap:8px;margin-bottom:24px;flex-wrap:wrap}
.genre-tab-btn{display:flex;align-items:center;gap:8px;padding:7px 14px;border-radius:10px;border:1px solid var(--border2);background:var(--s1);color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;transition:all .15s}
.genre-tab-btn:hover{background:var(--s2);color:var(--text)}
.genre-tab-btn.active{background:var(--s2);color:var(--text);font-weight:500;border-color:var(--gc,var(--fire));box-shadow:0 0 0 1px var(--gc,var(--fire)) inset}
.gtab-pill{font-family:'DM Mono',monospace;font-size:10px;padding:2px 7px;border-radius:20px;background:rgba(255,255,255,.05)}
.genre-tab-btn.active .gtab-pill{background:var(--gc,var(--fire));color:#fff;opacity:.9}
.add-genre-btn{display:flex;align-items:center;gap:5px;padding:7px 12px;border-radius:10px;border:1.5px dashed var(--border2);background:transparent;color:var(--muted);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12px;transition:all .15s;white-space:nowrap}
.add-genre-btn:hover{border-color:var(--gold);color:var(--gold)}

/* COLOR PICKER */
.color-swatches{display:flex;gap:8px;flex-wrap:wrap}
.color-swatch{width:32px;height:32px;border-radius:8px;border:2px solid transparent;cursor:pointer;transition:transform .1s,border-color .1s}
.color-swatch:hover{transform:scale(1.1)}
.color-swatch.selected{border-color:white}

/* GENRE HEADER */
.genre-header{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px}
.genre-title{font-family:'Syne',sans-serif;font-size:22px;font-weight:700;line-height:1}
.genre-subtitle{font-size:12px;color:var(--muted);margin-top:4px;font-family:'DM Mono',monospace}
.genre-progress-info{text-align:right}
.gp-num{font-family:'Syne',sans-serif;font-size:28px;font-weight:700;line-height:1}
.gp-label{font-size:11px;color:var(--muted);margin-top:2px}
.progress-track{height:4px;background:var(--s2);border-radius:4px;overflow:hidden;margin-bottom:20px}
.progress-fill{height:100%;border-radius:4px;transition:width .6s cubic-bezier(.25,1,.5,1)}

/* VIEW CONTROLS */
.view-controls{display:flex;align-items:center;justify-content:space-between;margin-bottom:20px;flex-wrap:wrap;gap:10px}
.view-tabs{display:flex;background:var(--s1);border:1px solid var(--border);border-radius:10px;padding:3px;gap:2px}
.view-tab{padding:6px 14px;border-radius:7px;border:none;background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12.5px;transition:all .15s}
.view-tab.active{background:var(--s3);color:var(--text);font-weight:500}
.filter-tabs{display:flex;gap:6px;flex-wrap:wrap}
.filter-tab{padding:5px 11px;border-radius:8px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-size:11.5px;font-family:'DM Sans',sans-serif;transition:all .15s}
.filter-tab:hover{border-color:var(--border2);color:var(--muted2)}
.filter-tab.active{border-color:var(--border2);color:var(--text);background:var(--s2)}

/* MOVES GRID */
.moves-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:10px}
.move-card{background:var(--s1);border:1px solid var(--border);border-radius:14px;padding:13px 13px 11px;transition:all .2s;position:relative}
.move-card:hover{border-color:var(--border2);background:var(--s2)}
.move-card.learned{border-color:rgba(255,255,255,.09)}
.mc-top{display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:8px}
.mc-name{font-size:13.5px;font-weight:500;line-height:1.3;flex:1}
.mc-custom-tag{font-size:9px;font-family:'DM Mono',monospace;background:rgba(192,132,252,.15);color:#C084FC;border:1px solid rgba(192,132,252,.25);border-radius:4px;padding:1px 5px;margin-top:2px;display:inline-block}
.mc-actions{display:flex;gap:4px;flex-shrink:0}
.learned-btn{width:26px;height:26px;border-radius:8px;border:1.5px solid var(--border2);background:transparent;color:var(--muted);cursor:pointer;font-size:13px;display:flex;align-items:center;justify-content:center;transition:all .15s}
.learned-btn:hover{border-color:rgba(255,255,255,.25);color:var(--text)}
.learned-btn.is-learned{color:#fff;border-color:transparent}
.edit-btn{width:26px;height:26px;border-radius:8px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-size:11px;display:flex;align-items:center;justify-content:center;transition:all .15s;opacity:0}
.move-card:hover .edit-btn{opacity:1}
.edit-btn:hover{border-color:var(--border2);color:var(--text);background:var(--s3)}
.mc-meta{display:flex;align-items:center;gap:6px;flex-wrap:wrap}
.origin-badge{font-family:'DM Mono',monospace;font-size:9.5px;padding:2px 7px;border-radius:5px;background:color-mix(in srgb,var(--bc) 14%,transparent);color:var(--bc);border:1px solid color-mix(in srgb,var(--bc) 28%,transparent)}
.yt-btn{font-size:9.5px;font-family:'DM Mono',monospace;color:#FF0000;background:rgba(255,0,0,.1);border:1px solid rgba(255,0,0,.2);border-radius:5px;padding:2px 7px;text-decoration:none}
.comfort-row{display:flex;align-items:center;gap:4px;margin-top:8px;padding-top:8px;border-top:1px solid var(--border)}
.comfort-btn{font-size:15px;background:transparent;border:1px solid var(--border);border-radius:7px;padding:3px 6px;cursor:pointer;transition:all .15s;line-height:1}
.comfort-btn:hover,.comfort-btn.active{background:var(--s3);border-color:var(--border2)}
.comfort-text{font-size:10.5px;color:var(--muted);margin-left:2px;font-weight:300}
.add-move-card{background:transparent;border:1.5px dashed var(--border2);border-radius:14px;padding:14px;cursor:pointer;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:6px;min-height:80px;color:var(--muted);transition:all .15s}
.add-move-card:hover{border-color:var(--fire);color:var(--fire);background:rgba(255,77,28,.04)}
.amc-plus{font-size:20px;line-height:1}
.amc-label{font-size:11.5px}

/* ROADMAP */
.roadmap{display:flex;flex-direction:column;gap:24px}
.rl-header{display:flex;align-items:center;gap:12px;margin-bottom:12px}
.rl-name{font-family:'DM Mono',monospace;font-size:10.5px;text-transform:uppercase;letter-spacing:.14em;color:var(--muted);white-space:nowrap}
.rl-divider{flex:1;height:1px;background:var(--border)}
.rl-count{font-family:'DM Mono',monospace;font-size:10.5px;color:var(--muted);white-space:nowrap}
.roadmap-add-btn{display:inline-flex;align-items:center;gap:6px;padding:8px 16px;border-radius:10px;border:1.5px dashed var(--border2);background:transparent;color:var(--muted);cursor:pointer;font-size:12.5px;font-family:'DM Sans',sans-serif;transition:all .15s;margin-top:4px}
.roadmap-add-btn:hover{border-color:var(--fire);color:var(--fire)}

/* MODAL (shared) */
.modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.65);backdrop-filter:blur(6px);display:flex;align-items:center;justify-content:center;z-index:100;padding:20px}
.modal{background:var(--s1);border:1px solid var(--border2);border-radius:20px;width:100%;max-width:420px;overflow:hidden;animation:modalIn .2s cubic-bezier(.34,1.56,.64,1)}
@keyframes modalIn{from{opacity:0;transform:scale(.92) translateY(12px)}to{opacity:1;transform:scale(1) translateY(0)}}
.modal-header{display:flex;align-items:center;justify-content:space-between;padding:20px 20px 16px;border-bottom:1px solid var(--border)}
.modal-title{font-family:'Syne',sans-serif;font-size:17px;font-weight:700}
.modal-close{width:28px;height:28px;border-radius:8px;border:none;background:var(--s2);color:var(--muted2);cursor:pointer;font-size:12px;display:flex;align-items:center;justify-content:center;transition:all .15s}
.modal-close:hover{background:var(--s3);color:var(--text)}
.modal-body{padding:18px 20px;display:flex;flex-direction:column;gap:14px}
.field-label{display:block;font-size:10.5px;font-family:'DM Mono',monospace;letter-spacing:.12em;text-transform:uppercase;color:var(--muted);margin-bottom:6px}
.field-input,.field-select{width:100%;background:var(--s2);border:1px solid var(--border2);border-radius:10px;padding:9px 13px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13.5px;font-weight:300;outline:none;transition:border-color .15s}
.field-input::placeholder{color:var(--muted);opacity:.7}
.field-input:focus,.field-select:focus{border-color:rgba(255,77,28,.5)}
.field-select{appearance:none;cursor:pointer}
.pick-row{display:flex;gap:6px;flex-wrap:wrap}
.pick-btn{padding:6px 12px;border-radius:8px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-size:12px;font-family:'DM Sans',sans-serif;transition:all .15s}
.pick-btn.sel{border-color:var(--pc);color:var(--pc);background:color-mix(in srgb,var(--pc) 12%,transparent)}
.modal-footer{display:flex;gap:8px;padding:14px 20px 20px;border-top:1px solid var(--border)}
.btn-cancel{flex:1;padding:10px;border-radius:10px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;transition:all .15s}
.btn-cancel:hover{background:var(--s2);color:var(--text)}
.btn-primary{flex:2;padding:10px;border-radius:10px;border:none;background:var(--fire);color:#fff;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:500;transition:opacity .15s}
.btn-primary:hover{opacity:.88}
.btn-primary:disabled{opacity:.35;cursor:default}

/* CHECKBOX */
.check-row{display:flex;align-items:center;gap:8px;cursor:pointer;user-select:none}
.check-box{width:18px;height:18px;border-radius:5px;border:1.5px solid var(--border2);background:transparent;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:all .15s}
.check-box.checked{background:var(--fire);border-color:var(--fire)}
.check-label{font-size:12.5px;color:var(--muted2);font-weight:300}

/* SHOWCASES LIST */
.sc-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px;margin-bottom:20px}
.sc-card{background:var(--s1);border:1px solid var(--border);border-radius:16px;padding:18px 18px 16px;cursor:pointer;transition:all .2s}
.sc-card:hover{border-color:var(--border2);background:var(--s2)}
.sc-card-top{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:10px}
.sc-card-name{font-family:'Syne',sans-serif;font-size:15px;font-weight:700;line-height:1.2}
.sc-card-arrow{font-size:16px;color:var(--muted)}
.sc-card-meta{display:flex;gap:6px;flex-wrap:wrap}
.chip{font-family:'DM Mono',monospace;font-size:10px;padding:3px 8px;border-radius:6px;background:var(--s3);color:var(--muted2)}
.sc-empty{text-align:center;padding:60px 0;color:var(--muted)}
.sc-empty-icon{font-size:40px;margin-bottom:12px}
.sc-empty-title{font-family:'Syne',sans-serif;font-size:17px;font-weight:700;color:var(--muted2);margin-bottom:6px}
.sc-empty-sub{font-size:13px;font-weight:300;margin-bottom:20px}
.btn-new{display:inline-flex;align-items:center;gap:8px;padding:10px 20px;border-radius:12px;border:none;background:var(--fire);color:#fff;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:500;transition:opacity .15s}
.btn-new:hover{opacity:.88}

/* SHOWCASE DETAIL */
.sc-detail{max-width:720px}
.sc-detail-header{display:flex;align-items:center;gap:10px;margin-bottom:8px;flex-wrap:wrap}
.back-btn{display:flex;align-items:center;gap:5px;padding:7px 12px;border-radius:10px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12.5px;transition:all .15s;flex-shrink:0}
.back-btn:hover{background:var(--s2);color:var(--text)}
.sc-detail-name{font-family:'Syne',sans-serif;font-size:22px;font-weight:800;flex:1;line-height:1.1}
.sc-detail-meta{display:flex;gap:8px;margin-bottom:28px;flex-wrap:wrap}

/* SUBSECTIONS */
.subsection{margin-bottom:28px}
.sub-header{display:flex;align-items:center;gap:10px;margin-bottom:12px}
.sub-name{font-family:'DM Mono',monospace;font-size:10.5px;text-transform:uppercase;letter-spacing:.15em;color:var(--muted);white-space:nowrap}
.sub-line{flex:1;height:1px;background:var(--border)}
.sub-del{width:22px;height:22px;border-radius:6px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-size:10px;display:flex;align-items:center;justify-content:center;transition:all .15s}
.sub-del:hover{border-color:rgba(255,80,80,.4);color:#ff6b6b}
.entries-row{display:flex;gap:8px;flex-wrap:wrap;align-items:stretch}
.entry-card{background:var(--s1);border:1px solid var(--border);border-radius:12px;padding:12px 14px;cursor:pointer;transition:all .2s;min-width:100px}
.entry-card:hover{border-color:var(--ec,var(--border2));background:var(--s2)}
.entry-card-label{font-size:13.5px;font-weight:600;color:var(--ec,var(--text));margin-bottom:4px;line-height:1.2}
.entry-card-count{font-family:'DM Mono',monospace;font-size:9.5px;color:var(--muted)}
.add-entry-card{background:transparent;border:1.5px dashed var(--border2);border-radius:12px;padding:12px 14px;cursor:pointer;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:3px;min-width:90px;color:var(--muted);font-family:'DM Sans',sans-serif;font-size:11px;transition:all .15s}
.add-entry-card:hover{border-color:var(--fire);color:var(--fire)}
.sub-add-btn{display:inline-flex;align-items:center;gap:6px;padding:8px 16px;border-radius:10px;border:1.5px dashed var(--border2);background:transparent;color:var(--muted);cursor:pointer;font-size:12.5px;font-family:'DM Sans',sans-serif;transition:all .15s;margin-top:8px}
.sub-add-btn:hover{border-color:var(--gold);color:var(--gold)}

/* ENTRY DETAIL */
.entry-detail{max-width:580px}
.entry-breadcrumb{display:flex;align-items:center;gap:8px;margin-bottom:20px;flex-wrap:wrap}
.breadcrumb-sep{color:var(--muted);font-size:14px}
.breadcrumb-sub{font-size:13px;color:var(--muted2)}
.breadcrumb-entry{font-family:'Syne',sans-serif;font-size:13px;font-weight:700}
.entry-detail-header{display:flex;align-items:center;gap:10px;margin-bottom:20px;flex-wrap:wrap}
.entry-detail-title{font-family:'Syne',sans-serif;font-size:20px;font-weight:800;flex:1}
.repaso-btn{display:flex;align-items:center;gap:6px;padding:8px 16px;border-radius:10px;border:none;background:var(--gold);color:var(--bg);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:600;transition:opacity .15s;flex-shrink:0}
.repaso-btn:hover{opacity:.88}
.repaso-btn:disabled{opacity:.3;cursor:default}
.seq-list{display:flex;flex-direction:column;gap:8px;margin-bottom:12px}
.seq-item{background:var(--s1);border:1px solid var(--border);border-radius:12px;padding:10px 14px;display:flex;align-items:center;gap:12px;transition:border-color .15s}
.seq-item:hover{border-color:var(--border2)}
.seq-num{font-family:'DM Mono',monospace;font-size:11px;color:var(--muted);width:20px;text-align:right;flex-shrink:0}
.seq-name{flex:1;font-size:14px;font-weight:500}
.seq-controls{display:flex;gap:4px;flex-shrink:0}
.seq-btn{width:26px;height:26px;border-radius:7px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-size:12px;display:flex;align-items:center;justify-content:center;transition:all .15s}
.seq-btn:hover:not(:disabled){border-color:var(--border2);color:var(--text);background:var(--s2)}
.seq-btn:disabled{opacity:.2;cursor:default}
.seq-btn.del:hover:not(:disabled){border-color:rgba(255,80,80,.4);color:#ff6b6b}
.seq-add-btn{display:flex;align-items:center;justify-content:center;gap:8px;width:100%;padding:10px;border-radius:12px;border:1.5px dashed var(--border2);background:transparent;color:var(--muted);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;transition:all .15s}
.seq-add-btn:hover{border-color:var(--fire);color:var(--fire);background:rgba(255,77,28,.04)}
.seq-empty{text-align:center;padding:28px 0;color:var(--muted);font-size:13px;font-weight:300}

/* MOVE PICKER */
.picker-tabs{display:flex;background:var(--s2);border-radius:10px;padding:3px;gap:2px;margin-bottom:14px}
.picker-tab{flex:1;padding:7px;border-radius:7px;border:none;background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12.5px;transition:all .15s;text-align:center}
.picker-tab.active{background:var(--s3);color:var(--text);font-weight:500}
.picker-search{width:100%;background:var(--s2);border:1px solid var(--border2);border-radius:10px;padding:8px 13px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;margin-bottom:10px}
.picker-search::placeholder{color:var(--muted);opacity:.7}
.picker-search:focus{border-color:rgba(255,77,28,.5)}
.picker-moves{display:flex;flex-direction:column;gap:5px;max-height:220px;overflow-y:auto;scrollbar-width:thin;scrollbar-color:rgba(255,255,255,.1) transparent}
.picker-move-btn{display:flex;align-items:center;justify-content:space-between;padding:9px 12px;border-radius:10px;border:1px solid var(--border);background:transparent;color:var(--text);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;text-align:left;transition:all .15s}
.picker-move-btn:hover{border-color:var(--border2);background:var(--s2)}
.picker-move-genre{font-family:'DM Mono',monospace;font-size:9.5px;color:var(--muted);flex-shrink:0}
.picker-none{text-align:center;padding:20px;color:var(--muted);font-size:13px}

/* REPASO MODE */
.repaso-overlay{position:fixed;inset:0;background:#070402;z-index:200;display:flex;flex-direction:column;animation:fadeIn .2s ease}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
.repaso-top{display:flex;align-items:center;justify-content:space-between;padding:20px 24px 0}
.repaso-exit{padding:7px 14px;border-radius:10px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12.5px;transition:all .15s}
.repaso-exit:hover{background:var(--s2);color:var(--text)}
.repaso-title-small{font-size:11px;font-family:'DM Mono',monospace;color:var(--muted);letter-spacing:.06em}
.repaso-counter{font-family:'DM Mono',monospace;font-size:12px;color:var(--muted);letter-spacing:.1em}
.repaso-prog-track{height:3px;background:var(--s2);margin:18px 0 0}
.repaso-prog-fill{height:100%;background:var(--fire);transition:width .3s ease}
.repaso-main{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:32px;gap:10px}
.repaso-step-label{font-size:12px;color:var(--muted);font-family:'DM Mono',monospace;letter-spacing:.08em}
.repaso-move-name{font-family:'Syne',sans-serif;font-size:clamp(30px,7vw,50px);font-weight:800;text-align:center;line-height:1.1;animation:slideUp .25s ease}
@keyframes slideUp{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
.repaso-nav{display:flex;gap:10px;padding:20px 24px 28px;justify-content:center}
.repaso-nav-btn{flex:1;max-width:160px;padding:13px;border-radius:13px;border:1px solid var(--border2);background:var(--s1);color:var(--text);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:14px;font-weight:500;transition:all .15s}
.repaso-nav-btn:hover:not(:disabled){background:var(--s2)}
.repaso-nav-btn:disabled{opacity:.2;cursor:default}
.repaso-nav-btn.next{background:var(--fire);border-color:var(--fire);color:#fff}
.repaso-nav-btn.next:hover{opacity:.88}
.repaso-done{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:14px}
.repaso-done-icon{font-size:56px}
.repaso-done-title{font-family:'Syne',sans-serif;font-size:28px;font-weight:800}
.repaso-done-sub{font-size:13px;color:var(--muted);font-weight:300}
.repaso-restart{padding:9px 22px;border-radius:11px;border:none;background:var(--s2);color:var(--text);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px}
.repaso-restart:hover{background:var(--s3)}

/* COMING SOON */
.coming-soon{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:60vh;gap:12px;color:var(--muted)}
.cs-icon{font-size:40px;margin-bottom:4px}
.cs-title{font-family:'Syne',sans-serif;font-size:20px;font-weight:700;color:var(--muted2)}
.cs-sub{font-size:13px;font-weight:300}

/* MOBILE */
@media(max-width:700px){
  .app{grid-template-columns:1fr}
  .sidebar{display:none}
  .main{padding-bottom:72px}
  .bottom-nav{display:flex}
  .section{padding:24px 16px 20px}
  .moves-grid{grid-template-columns:repeat(auto-fill,minmax(160px,1fr))}
  .edit-btn{opacity:1}
  .sc-grid{grid-template-columns:1fr}
  .cal-grid{grid-template-columns:repeat(7,1fr)}
  .cal-cell{min-height:52px;padding:6px 4px 4px}
  .cal-day-num{font-size:11px}
}

/* ── CALENDAR ── */
.cal-section{padding:32px 24px 60px;max-width:960px}
.cal-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:16px}
.cal-nav{display:flex;align-items:center;gap:10px}
.cal-nav-btn{width:32px;height:32px;border-radius:9px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center;transition:all .15s}
.cal-nav-btn:hover{background:var(--s2);color:var(--text)}
.cal-month{font-family:'Syne',sans-serif;font-size:18px;font-weight:700;min-width:180px;text-align:center}
.cal-today-btn{padding:5px 13px;border-radius:8px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12px;transition:all .15s}
.cal-today-btn:hover{background:var(--s2);color:var(--text)}
.cal-summary{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px}
.cal-sum-chip{display:flex;align-items:center;gap:5px;padding:4px 10px;border-radius:7px;background:var(--s1);border:1px solid var(--border);font-size:11.5px;color:var(--muted2)}
.cal-sum-dot{width:7px;height:7px;border-radius:50%;flex-shrink:0}
.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:4px}
.cal-day-hdr{font-family:'DM Mono',monospace;font-size:10px;text-align:center;padding:6px 0 8px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em}
.cal-cell{min-height:74px;border-radius:10px;padding:8px 7px 6px;cursor:pointer;transition:background .15s;border:1px solid transparent;position:relative}
.cal-cell:hover:not(.other-month){background:var(--s2)}
.cal-cell.other-month{opacity:.2;pointer-events:none}
.cal-cell.today{border-color:var(--fire)}
.cal-cell.has-session{background:var(--s1)}
.cal-cell.has-session:hover{background:var(--s2)}
.cal-day-num{font-size:12.5px;font-weight:500;color:var(--muted2);line-height:1;margin-bottom:5px}
.cal-cell.today .cal-day-num{color:var(--fire);font-weight:700}
.cal-dots{display:flex;gap:3px;flex-wrap:wrap;align-items:center;margin-bottom:3px}
.cal-dot{width:7px;height:7px;border-radius:50%;flex-shrink:0}
.cal-type-label{font-size:9.5px;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;line-height:1.2}

/* SESSION MODAL */
.session-modal{max-width:500px}
.session-tabs{display:flex;background:var(--s2);border-radius:10px;padding:3px;gap:2px;margin-bottom:16px}
.session-tab{flex:1;padding:8px;border-radius:7px;border:none;background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;transition:all .15s;text-align:center;display:flex;align-items:center;justify-content:center;gap:6px}
.session-tab.active{background:var(--s3);color:var(--text);font-weight:500}
.type-grid{display:flex;gap:6px;flex-wrap:wrap}
.type-btn{display:flex;align-items:center;gap:5px;padding:7px 12px;border-radius:9px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12px;transition:all .15s}
.type-btn:hover{border-color:rgba(255,255,255,.2);color:var(--text)}
.type-btn.sel{border-color:var(--tc);color:var(--tc);background:color-mix(in srgb,var(--tc) 12%,transparent)}
.level-row{display:flex;gap:8px}
.level-btn{flex:1;padding:9px;border-radius:9px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:13px;text-align:center;transition:all .15s}
.level-btn.sel{border-color:var(--gold);color:var(--gold);background:rgba(255,184,0,.1)}
.mood-picker{display:flex;gap:6px}
.mood-btn{flex:1;display:flex;flex-direction:column;align-items:center;gap:3px;padding:8px 4px;border-radius:10px;border:1px solid var(--border);background:transparent;cursor:pointer;transition:all .15s}
.mood-btn:hover{border-color:var(--border2);background:var(--s2)}
.mood-btn.sel{border-color:rgba(255,184,0,.5);background:rgba(255,184,0,.1)}
.mood-emoji{font-size:20px;line-height:1}
.mood-lbl{font-size:8.5px;color:var(--muted);font-family:'DM Mono',monospace;text-align:center}
.moves-log-area{display:flex;flex-wrap:wrap;gap:6px;min-height:34px;align-items:center;margin-bottom:8px;padding:6px 0}
.move-log-tag{display:inline-flex;align-items:center;gap:5px;padding:4px 9px;border-radius:7px;background:var(--s3);border:1px solid var(--border2);font-size:12.5px}
.move-log-tag button{background:none;border:none;color:var(--muted);cursor:pointer;font-size:10px;padding:0;line-height:1;transition:color .15s}
.move-log-tag button:hover{color:var(--text)}
.log-add-btn{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;border-radius:7px;border:1.5px dashed var(--border2);background:transparent;color:var(--muted);cursor:pointer;font-size:12px;font-family:'DM Sans',sans-serif;transition:all .15s}
.log-add-btn:hover{border-color:var(--fire);color:var(--fire)}
.log-notes{width:100%;background:var(--s2);border:1px solid var(--border2);border-radius:10px;padding:9px 13px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;font-weight:300;outline:none;resize:vertical;min-height:68px;transition:border-color .15s}
.log-notes:focus{border-color:rgba(255,77,28,.5)}
.log-notes::placeholder{color:var(--muted);opacity:.6}
.del-btn{padding:8px 14px;border-radius:10px;border:1px solid rgba(255,80,80,.3);background:transparent;color:rgba(255,100,100,.8);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12.5px;transition:all .15s}
.del-btn:hover{background:rgba(255,80,80,.08);border-color:rgba(255,80,80,.5)}
.logged-badge{font-size:10px;background:rgba(52,211,153,.12);border:1px solid rgba(52,211,153,.3);color:#34D399;border-radius:5px;padding:1px 6px;font-family:'DM Mono',monospace}

/* ── DASHBOARD ── */
.dash-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:24px}
.dash-stat{background:var(--s1);border:1px solid var(--border);border-radius:16px;padding:18px 20px}
.dash-stat-num{font-family:'Syne',sans-serif;font-size:36px;font-weight:800;line-height:1;margin-bottom:4px}
.dash-stat-label{font-size:10.5px;text-transform:uppercase;letter-spacing:.14em;color:var(--muted);font-family:'DM Mono',monospace}
.dash-stat-sub{font-size:11px;color:var(--muted);margin-top:4px;font-weight:300}
.dash-row{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px}
.dash-card{background:var(--s1);border:1px solid var(--border);border-radius:16px;padding:18px 20px}
.dash-card-full{background:var(--s1);border:1px solid var(--border);border-radius:16px;padding:18px 20px;margin-bottom:12px}
.dash-card-title{font-size:10.5px;text-transform:uppercase;letter-spacing:.14em;color:var(--muted);font-family:'DM Mono',monospace;margin-bottom:14px}
.dash-bar-row{display:flex;align-items:center;gap:10px;margin-bottom:9px}
.dash-bar-label{font-size:12.5px;width:90px;flex-shrink:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.dash-bar-track{flex:1;height:6px;background:var(--s3);border-radius:6px;overflow:hidden}
.dash-bar-fill{height:100%;border-radius:6px;transition:width .6s cubic-bezier(.25,1,.5,1)}
.dash-bar-count{font-family:'DM Mono',monospace;font-size:11px;color:var(--muted);width:20px;text-align:right;flex-shrink:0}
.dash-split{display:flex;gap:8px}
.dash-split-item{flex:1;display:flex;flex-direction:column;align-items:center;gap:6px;padding:14px 8px;background:var(--s2);border-radius:12px}
.dash-split-emoji{font-size:22px;line-height:1}
.dash-split-num{font-family:'Syne',sans-serif;font-size:22px;font-weight:700;line-height:1}
.dash-split-label{font-size:10px;color:var(--muted);font-family:'DM Mono',monospace;text-align:center}
.dash-mood-row{display:flex;gap:6px;align-items:flex-end;height:56px;margin-bottom:10px}
.dash-mood-bar{flex:1;display:flex;flex-direction:column;align-items:center;gap:4px;height:100%}
.dash-mood-fill{width:100%;border-radius:4px 4px 0 0;transition:height .5s cubic-bezier(.25,1,.5,1);min-height:3px}
.dash-mood-emoji{font-size:14px;line-height:1}
.dash-mood-count{font-size:10px;color:var(--muted);font-family:'DM Mono',monospace}
.dash-recent-item{display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid var(--border)}
.dash-recent-item:last-child{border-bottom:none}
.dash-recent-dot{width:9px;height:9px;border-radius:50%;flex-shrink:0}
.dash-recent-info{flex:1;min-width:0}
.dash-recent-date{font-size:11px;color:var(--muted);font-family:'DM Mono',monospace;margin-bottom:2px}
.dash-recent-title{font-size:13.5px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.dash-recent-notes{font-size:11.5px;color:var(--muted);font-weight:300;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-top:2px}
.dash-recent-mood{font-size:16px;flex-shrink:0}
.dash-empty{text-align:center;padding:40px 0;color:var(--muted);font-size:13px;font-weight:300}
@media(max-width:700px){
  .dash-grid{grid-template-columns:repeat(2,1fr)}
  .dash-row{grid-template-columns:1fr}
}

/* ── PROFILE ── */
.profile-card{background:var(--s1);border:1px solid var(--border);border-radius:20px;padding:28px;margin-bottom:16px;max-width:560px}
.profile-avatar{width:68px;height:68px;border-radius:18px;background:linear-gradient(135deg,var(--fire),var(--gold));display:flex;align-items:center;justify-content:center;font-size:26px;margin-bottom:20px}
.profile-name-row{display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:20px}
.profile-name{font-family:'Syne',sans-serif;font-size:24px;font-weight:800;line-height:1.1}
.profile-since{font-size:11.5px;color:var(--muted);margin-top:4px;font-family:'DM Mono',monospace}
.profile-edit-btn{padding:7px 14px;border-radius:9px;border:1px solid var(--border2);background:transparent;color:var(--muted2);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:12px;transition:all .15s;flex-shrink:0}
.profile-edit-btn:hover{background:var(--s2);color:var(--text)}
.profile-fields{display:grid;grid-template-columns:1fr 1fr;gap:14px 24px}
.profile-field-label{font-size:10px;text-transform:uppercase;letter-spacing:.15em;color:var(--muted);font-family:'DM Mono',monospace;margin-bottom:4px}
.profile-field-value{font-size:13.5px;color:var(--text)}
.profile-field-empty{font-size:13px;color:var(--muted);font-style:italic}
.profile-divider{height:1px;background:var(--border);margin:20px 0}
.profile-stats-row{display:flex;gap:0}
.profile-stat{flex:1;text-align:center;padding:4px 0}
.profile-stat+.profile-stat{border-left:1px solid var(--border)}
.profile-stat-num{font-family:'Syne',sans-serif;font-size:26px;font-weight:800;color:var(--fire);line-height:1}
.profile-stat-label{font-size:9.5px;color:var(--muted);text-transform:uppercase;letter-spacing:.12em;font-family:'DM Mono',monospace;margin-top:3px}
.profile-notes-card{background:var(--s1);border:1px solid var(--border);border-radius:16px;padding:20px;max-width:560px}
.profile-save-row{display:flex;gap:8px;margin-top:4px}
@media(max-width:700px){.profile-fields{grid-template-columns:1fr}}

/* ── CHAT ── */
.chat-section{display:flex;flex-direction:column;height:calc(100vh - 0px);max-height:100vh}
.chat-header-bar{padding:20px 24px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;flex-shrink:0}
.chat-header-info{display:flex;align-items:center;gap:12px}
.chat-avatar{width:38px;height:38px;border-radius:11px;background:linear-gradient(135deg,var(--fire),var(--gold));display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0}
.chat-header-name{font-family:'Syne',sans-serif;font-size:16px;font-weight:700}
.chat-header-status{font-size:11px;color:var(--gold);opacity:.75;margin-top:1px}
.chat-clear-btn{padding:5px 12px;border-radius:8px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:11.5px;transition:all .15s}
.chat-clear-btn:hover{border-color:var(--border2);color:var(--muted2)}
.chat-messages{flex:1;overflow-y:auto;padding:20px 24px;display:flex;flex-direction:column;gap:16px;scrollbar-width:thin;scrollbar-color:rgba(255,255,255,.08) transparent}
.chat-msg{max-width:82%;animation:msgIn .25s ease}
@keyframes msgIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
.chat-msg.user{align-self:flex-end}
.chat-msg.assistant{align-self:flex-start}
.chat-bubble{padding:10px 14px;border-radius:16px;font-size:13.5px;line-height:1.6;font-weight:300;white-space:pre-wrap}
.chat-msg.user .chat-bubble{background:linear-gradient(135deg,var(--fire),#e03a0a);color:#fff;border-bottom-right-radius:4px}
.chat-msg.assistant .chat-bubble{background:var(--s2);border:1px solid var(--border2);color:var(--text);border-bottom-left-radius:4px}
.chat-time{font-size:10px;color:var(--muted);margin-top:4px;padding:0 4px}
.chat-msg.user .chat-time{text-align:right}
.typing-indicator{display:flex;gap:4px;align-items:center;padding:12px 16px;background:var(--s2);border:1px solid var(--border2);border-radius:16px;border-bottom-left-radius:4px;width:fit-content}
.typing-dot{width:6px;height:6px;background:var(--gold);border-radius:50%;animation:typingBounce 1.2s ease-in-out infinite}
.typing-dot:nth-child(2){animation-delay:.2s}
.typing-dot:nth-child(3){animation-delay:.4s}
@keyframes typingBounce{0%,80%,100%{transform:translateY(0);opacity:.4}40%{transform:translateY(-6px);opacity:1}}
.chat-input-row{padding:14px 20px calc(14px + env(safe-area-inset-bottom));border-top:1px solid var(--border);display:flex;gap:10px;align-items:flex-end;flex-shrink:0}
.chat-input{flex:1;background:var(--s2);border:1px solid var(--border2);border-radius:14px;padding:10px 14px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13.5px;font-weight:300;resize:none;outline:none;min-height:42px;max-height:120px;line-height:1.5;transition:border-color .15s}
.chat-input::placeholder{opacity:.4}
.chat-input:focus{border-color:rgba(255,77,28,.5)}
.chat-send-btn{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--fire),#e03a0a);border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;color:#fff;font-size:17px;flex-shrink:0;transition:all .15s}
.chat-send-btn:hover{transform:scale(1.06);box-shadow:0 4px 20px rgba(255,77,28,.4)}
.chat-send-btn:disabled{opacity:.35;cursor:default;transform:none;box-shadow:none}
`;




// ═══════════════════════════════════════════════════════════════
// REPERTORIO COMPONENTS
// ═══════════════════════════════════════════════════════════════

function MoveModal({ initial, onSave, onClose }) {
  const isEdit = !!initial;
  const [name,    setName]    = useState(initial?.name    ?? "");
  const [origin,  setOrigin]  = useState(initial?.origin  ?? "AM");
  const [level,   setLevel]   = useState(initial?.level   ?? "Fundamentos");
  const [youtube, setYoutube] = useState(initial?.youtube ?? "");
  function handleSave() {
    if (!name.trim()) return;
    onSave({...(initial??{id:`custom-${Date.now()}`,learned:false,comfort:null,custom:true}),name:name.trim(),origin,level,youtube:youtube.trim()||null});
    onClose();
  }
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div className="modal-header">
          <span className="modal-title">{isEdit?"Editar paso":"Agregar paso"}</span>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <div><label className="field-label">Nombre</label>
            <input className="field-input" placeholder="ej. Inside Turn..." value={name}
              onChange={e=>setName(e.target.value)}
              onKeyDown={e=>{if(e.key==="Enter")handleSave();if(e.key==="Escape")onClose();}} autoFocus/>
          </div>
          <div><label className="field-label">Origen</label>
            <div className="pick-row">{ORIGINS.map(o=>(
              <button key={o.id} className={`pick-btn ${origin===o.id?"sel":""}`}
                style={{"--pc":o.color}} onClick={()=>setOrigin(o.id)}>{o.label}</button>
            ))}</div>
          </div>
          <div><label className="field-label">Nivel</label>
            <select className="field-select" value={level} onChange={e=>setLevel(e.target.value)}>
              {LEVELS.map(l=><option key={l} value={l}>{l}</option>)}</select>
          </div>
          <div><label className="field-label">YouTube (opcional)</label>
            <input className="field-input" placeholder="https://youtube.com/..." value={youtube} onChange={e=>setYoutube(e.target.value)}/>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-cancel" onClick={onClose}>Cancelar</button>
          <button className="btn-primary" onClick={handleSave} disabled={!name.trim()}>{isEdit?"Guardar":"Agregar"}</button>
        </div>
      </div>
    </div>
  );
}

function AddGenreModal({ onSave, onClose }) {
  const [name,  setName]  = useState("");
  const [color, setColor] = useState(GENRE_COLORS[4]);
  const [sub,   setSub]   = useState("");
  function handleSave() {
    if (!name.trim()) return;
    onSave({id:`genre-${Date.now()}`,name:name.trim(),sub:sub.trim(),color,moves:[]});
    onClose();
  }
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div className="modal-header">
          <span className="modal-title">Nuevo género</span>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <div><label className="field-label">Nombre</label>
            <input className="field-input" placeholder="ej. Cha Cha, Swing, Cumbia..."
              value={name} onChange={e=>setName(e.target.value)}
              onKeyDown={e=>{if(e.key==="Enter")handleSave();if(e.key==="Escape")onClose();}} autoFocus/>
          </div>
          <div><label className="field-label">Subtítulo (opcional)</label>
            <input className="field-input" placeholder="ej. Estilo cubano, Social dance..." value={sub} onChange={e=>setSub(e.target.value)}/>
          </div>
          <div><label className="field-label">Color</label>
            <div className="color-swatches">
              {GENRE_COLORS.map(c=>(
                <div key={c} className={`color-swatch ${color===c?"selected":""}`}
                  style={{background:c}} onClick={()=>setColor(c)}/>
              ))}
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-cancel" onClick={onClose}>Cancelar</button>
          <button className="btn-primary" onClick={handleSave} disabled={!name.trim()}>Crear género</button>
        </div>
      </div>
    </div>
  );
}

function MoveCard({ move, genreColor, onUpdate, onEdit }) {
  const origin  = ORIGINS.find(o=>o.id===move.origin);
  const comfort = COMFORT.find(c=>c.id===move.comfort);
  return (
    <div className={`move-card ${move.learned?"learned":""}`}>
      <div className="mc-top">
        <div><div className="mc-name">{move.name}</div>
          {move.custom && <span className="mc-custom-tag">custom</span>}</div>
        <div className="mc-actions">
          <button className="edit-btn" onClick={()=>onEdit(move)}>✏️</button>
          <button className={`learned-btn ${move.learned?"is-learned":""}`}
            style={move.learned?{background:genreColor,borderColor:genreColor}:{}}
            onClick={()=>onUpdate({...move,learned:!move.learned,comfort:!move.learned?"new":null})}>
            {move.learned?"✓":"+"}
          </button>
        </div>
      </div>
      <div className="mc-meta">
        {origin && <span className="origin-badge" style={{"--bc":origin.color}}>{origin.label}</span>}
        {move.youtube && <a href={move.youtube} target="_blank" rel="noopener noreferrer" className="yt-btn">▶ Video</a>}
      </div>
      {move.learned && (
        <div className="comfort-row">
          {COMFORT.map(c=>(
            <button key={c.id} className={`comfort-btn ${move.comfort===c.id?"active":""}`}
              onClick={()=>onUpdate({...move,comfort:c.id})} title={c.label}>{c.emoji}</button>
          ))}
          {comfort && <span className="comfort-text">{comfort.label}</span>}
        </div>
      )}
    </div>
  );
}

function GenreView({ genre, onUpdateGenre }) {
  const [view,   setView]   = useState("roadmap");
  const [filter, setFilter] = useState("all");
  const [modal,  setModal]  = useState(null);
  const learned = genre.moves.filter(m=>m.learned);
  const pct = genre.moves.length ? Math.round(learned.length/genre.moves.length*100) : 0;
  const levels = LEVELS.filter(l=>genre.moves.some(m=>m.level===l));
  function updateMove(u){onUpdateGenre({...genre,moves:genre.moves.map(m=>m.id===u.id?u:m)});}
  function saveMove(m){const e=genre.moves.some(x=>x.id===m.id);onUpdateGenre({...genre,moves:e?genre.moves.map(x=>x.id===m.id?m:x):[...genre.moves,m]});}
  const filtered = genre.moves.filter(m=>{
    if(filter==="learned") return m.learned;
    if(filter==="pending") return !m.learned;
    return true;
  });
  const Grid = ({moves,showAdd})=>(
    <div className="moves-grid">
      {moves.map(m=><MoveCard key={m.id} move={m} genreColor={genre.color} onUpdate={updateMove} onEdit={m=>setModal(m)}/>)}
      {showAdd && <button className="add-move-card" onClick={()=>setModal("add")}><span className="amc-plus">+</span><span className="amc-label">Agregar paso</span></button>}
    </div>
  );
  return (
    <div>
      <div className="genre-header">
        <div><div className="genre-title" style={{color:genre.color}}>{genre.name}</div>
          {genre.sub && <div className="genre-subtitle">{genre.sub}</div>}</div>
        <div className="genre-progress-info">
          <div className="gp-num" style={{color:genre.color}}>{learned.length}</div>
          <div className="gp-label">de {genre.moves.length} pasos</div>
        </div>
      </div>
      <div className="progress-track"><div className="progress-fill" style={{width:`${pct}%`,background:genre.color}}/></div>
      <div className="view-controls">
        <div className="view-tabs">
          <button className={`view-tab ${view==="roadmap"?"active":""}`} onClick={()=>setView("roadmap")}>Roadmap</button>
          <button className={`view-tab ${view==="repertorio"?"active":""}`} onClick={()=>setView("repertorio")}>Mi repertorio</button>
        </div>
        <div className="filter-tabs">
          {[["all","Todos"],["learned","Aprendidos"],["pending","Pendientes"]].map(([id,lbl])=>(
            <button key={id} className={`filter-tab ${filter===id?"active":""}`} onClick={()=>setFilter(id)}>{lbl}</button>
          ))}
        </div>
      </div>
      {view==="roadmap"?(
        <div className="roadmap">
          {levels.map(level=>{
            const lv=filtered.filter(m=>m.level===level);if(!lv.length)return null;
            const lvl=lv.filter(m=>m.learned).length;
            return(<div key={level}>
              <div className="rl-header"><span className="rl-name">{level}</span><div className="rl-divider"/><span className="rl-count" style={lvl===lv.length?{color:genre.color}:{}}>{lvl}/{lv.length}</span></div>
              <Grid moves={lv} showAdd={false}/>
            </div>);
          })}
          <button className="roadmap-add-btn" onClick={()=>setModal("add")}>+ Agregar paso custom</button>
        </div>
      ):(
        learned.length===0
          ?<div style={{color:"var(--muted)",fontSize:13,padding:"40px 0",textAlign:"center"}}>Aún no marcaste ningún paso como aprendido</div>
          :<Grid moves={filtered.filter(m=>m.learned)} showAdd={true}/>
      )}
      {modal && <MoveModal initial={modal==="add"?null:modal} onSave={saveMove} onClose={()=>setModal(null)}/>}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// SHOWCASES — REPASO
// ═══════════════════════════════════════════════════════════════

function RepasoMode({ sequence, title, onClose }) {
  const [idx, setIdx] = useState(0);
  const done = idx >= sequence.length;
  return (
    <div className="repaso-overlay">
      <div className="repaso-top">
        <button className="repaso-exit" onClick={onClose}>← Salir</button>
        <span className="repaso-title-small">{title}</span>
        {!done && <span className="repaso-counter">{idx+1} / {sequence.length}</span>}
      </div>
      <div className="repaso-prog-track">
        <div className="repaso-prog-fill" style={{width:`${done?100:Math.round(idx/sequence.length*100)}%`}}/>
      </div>
      {done ? (
        <div className="repaso-done">
          <div className="repaso-done-icon">🎉</div>
          <div className="repaso-done-title">¡Listo!</div>
          <div className="repaso-done-sub">Repasaste los {sequence.length} pasos</div>
          <button className="repaso-restart" onClick={()=>setIdx(0)}>Repetir desde el inicio</button>
        </div>
      ):(
        <>
          <div className="repaso-main">
            <div className="repaso-step-label">PASO {idx+1}</div>
            <div className="repaso-move-name" key={idx}>{sequence[idx].name}</div>
          </div>
          <div className="repaso-nav">
            <button className="repaso-nav-btn" onClick={()=>setIdx(i=>i-1)} disabled={idx===0}>← Anterior</button>
            <button className="repaso-nav-btn next" onClick={()=>setIdx(i=>i+1)}>
              {idx===sequence.length-1?"Terminar ✓":"Siguiente →"}
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// SHOWCASES — MOVE PICKER
// fix #3: filtra por género de la entrada
// fix #2: opción de sync a repertorio en custom
// ═══════════════════════════════════════════════════════════════

function MovePicker({ genres, entryGenre, onAdd, onAddToRepertoire, onClose }) {
  const [tab,    setTab]    = useState("repertoire");
  const [search, setSearch] = useState("");
  const [custom, setCustom] = useState("");
  const [sync,   setSync]   = useState(true); // sync custom to repertoire

  // Filter learned moves by entry genre (if genre is not "coreo")
  const isCoreo = !entryGenre || entryGenre === "coreo";
  const learnedMoves = genres.flatMap(g =>
    (!isCoreo && g.id !== entryGenre) ? [] :
    g.moves.filter(m=>m.learned).map(m=>({...m,genreName:g.name,genreColor:g.color}))
  );
  const filtered = learnedMoves.filter(m=>m.name.toLowerCase().includes(search.toLowerCase()));

  const targetGenreName = genres.find(g=>g.id===entryGenre)?.name;

  function handleAddCustom() {
    if (!custom.trim()) return;
    onAdd(custom.trim());
    if (sync && !isCoreo && onAddToRepertoire) onAddToRepertoire(entryGenre, custom.trim());
    onClose();
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" style={{maxWidth:480}} onClick={e=>e.stopPropagation()}>
        <div className="modal-header">
          <span className="modal-title">Agregar paso a la secuencia</span>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body" style={{paddingBottom:8}}>
          <div className="picker-tabs">
            <button className={`picker-tab ${tab==="repertoire"?"active":""}`} onClick={()=>setTab("repertoire")}>
              {isCoreo ? "Del repertorio" : `Mis pasos de ${targetGenreName||""}`}
            </button>
            <button className={`picker-tab ${tab==="custom"?"active":""}`} onClick={()=>setTab("custom")}>Personalizado</button>
          </div>
          {tab==="repertoire"?(
            <>
              <input className="picker-search" placeholder="Buscar paso..." value={search} onChange={e=>setSearch(e.target.value)} autoFocus/>
              <div className="picker-moves">
                {filtered.length===0
                  ?<div className="picker-none">
                    {isCoreo?"Sin pasos aprendidos aún":
                     `Sin pasos aprendidos de ${targetGenreName} aún — marca algunos en Géneros primero, o usa "Personalizado"`}
                  </div>
                  :filtered.map(m=>(
                    <button key={`${m.id}-${m.genreName}`} className="picker-move-btn" onClick={()=>{onAdd(m.name);onClose();}}>
                      <span>{m.name}</span>
                      {isCoreo && <span className="picker-move-genre">{m.genreName}</span>}
                    </button>
                  ))
                }
              </div>
            </>
          ):(
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div>
                <label className="field-label">Nombre del paso</label>
                <input className="field-input" placeholder="ej. Basic Step, Catapulta..." value={custom}
                  onChange={e=>setCustom(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter"&&custom.trim())handleAddCustom();}} autoFocus/>
              </div>
              {!isCoreo && (
                <label className="check-row" onClick={()=>setSync(s=>!s)}>
                  <div className={`check-box ${sync?"checked":""}`}>{sync&&<span style={{color:"#fff",fontSize:11}}>✓</span>}</div>
                  <span className="check-label">Agregar también al repertorio de {targetGenreName}</span>
                </label>
              )}
            </div>
          )}
        </div>
        {tab==="custom" && (
          <div className="modal-footer">
            <button className="btn-cancel" onClick={onClose}>Cancelar</button>
            <button className="btn-primary" disabled={!custom.trim()} onClick={handleAddCustom}>Agregar</button>
          </div>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// SHOWCASES — ENTRY DETAIL
// ═══════════════════════════════════════════════════════════════

function EntryDetail({ entry, subsectionName, genres, onUpdate, onAddToRepertoire, onBack }) {
  const [showPicker, setShowPicker] = useState(false);
  const [showRepaso, setShowRepaso] = useState(false);
  const gi  = genres.find(g=>g.id===entry.genre) || COREO;
  const seq = entry.sequence;
  function addStep(name){ onUpdate({...entry,sequence:[...seq,{id:`step-${Date.now()}`,name}]}); }
  function moveUp(i){if(i===0)return;const s=[...seq];[s[i-1],s[i]]=[s[i],s[i-1]];onUpdate({...entry,sequence:s});}
  function moveDown(i){if(i===seq.length-1)return;const s=[...seq];[s[i],s[i+1]]=[s[i+1],s[i]];onUpdate({...entry,sequence:s});}
  function remove(i){onUpdate({...entry,sequence:seq.filter((_,j)=>j!==i)});}
  return (
    <div className="entry-detail">
      <div className="entry-breadcrumb">
        <button className="back-btn" onClick={onBack}>← Volver</button>
        <span className="breadcrumb-sep">/</span>
        <span className="breadcrumb-sub">{subsectionName}</span>
        <span className="breadcrumb-sep">/</span>
        <span className="breadcrumb-entry" style={{color:gi.color}}>{entry.label}</span>
      </div>
      <div className="entry-detail-header">
        <div className="entry-detail-title">{entry.label}</div>
        <button className="repaso-btn" onClick={()=>setShowRepaso(true)} disabled={seq.length===0}>▶ Repasar</button>
      </div>
      <div className="seq-list">
        {seq.length===0
          ?<div className="seq-empty">Sin pasos — agrega el primero abajo</div>
          :seq.map((step,i)=>(
            <div key={step.id} className="seq-item">
              <span className="seq-num">{i+1}</span>
              <span className="seq-name">{step.name}</span>
              <div className="seq-controls">
                <button className="seq-btn" onClick={()=>moveUp(i)} disabled={i===0}>↑</button>
                <button className="seq-btn" onClick={()=>moveDown(i)} disabled={i===seq.length-1}>↓</button>
                <button className="seq-btn del" onClick={()=>remove(i)}>✕</button>
              </div>
            </div>
          ))
        }
      </div>
      <button className="seq-add-btn" onClick={()=>setShowPicker(true)}>+ Agregar paso</button>
      {showPicker && <MovePicker genres={genres} entryGenre={entry.genre} onAdd={addStep} onAddToRepertoire={onAddToRepertoire} onClose={()=>setShowPicker(false)}/>}
      {showRepaso && <RepasoMode sequence={seq} title={`${subsectionName} · ${entry.label}`} onClose={()=>setShowRepaso(false)}/>}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// SHOWCASES — SHOWCASE DETAIL
// ═══════════════════════════════════════════════════════════════

function ShowcaseDetail({ showcase, genres, onUpdate, onAddToRepertoire, onBack }) {
  const [selectedEntry, setSelectedEntry] = useState(null);
  const [addSubModal,   setAddSubModal]   = useState(false);
  const [addEntryFor,   setAddEntryFor]   = useState(null);
  const [newSubName,    setNewSubName]    = useState("");
  const [newEntryGenre, setNewEntryGenre] = useState("salsa");
  const [newEntryLabel, setNewEntryLabel] = useState("");

  const entryGenreList = [...genres.map(g=>({id:g.id,name:g.name,color:g.color})), COREO];

  if (selectedEntry) {
    const sub   = showcase.subsections.find(s=>s.id===selectedEntry.subId);
    const entry = sub?.entries.find(e=>e.id===selectedEntry.entId);
    if (sub && entry) {
      function updateEntry(updated){
        const newSubs=showcase.subsections.map(s=>s.id===sub.id?{...s,entries:s.entries.map(e=>e.id===updated.id?updated:e)}:s);
        onUpdate({...showcase,subsections:newSubs});
      }
      return (
        <div className="section">
          <EntryDetail entry={entry} subsectionName={sub.name} genres={genres}
            onUpdate={updateEntry} onAddToRepertoire={onAddToRepertoire}
            onBack={()=>setSelectedEntry(null)}/>
        </div>
      );
    }
  }

  function addSub(){if(!newSubName.trim())return;const s={id:`sub-${Date.now()}`,name:newSubName.trim(),entries:[]};onUpdate({...showcase,subsections:[...showcase.subsections,s]});setNewSubName("");setAddSubModal(false);}
  function delSub(id){onUpdate({...showcase,subsections:showcase.subsections.filter(s=>s.id!==id)});}
  function addEntry(subId){
    const gi=entryGenreList.find(g=>g.id===newEntryGenre);
    const e={id:`ent-${Date.now()}`,genre:newEntryGenre,label:newEntryLabel.trim()||gi.name,sequence:[]};
    onUpdate({...showcase,subsections:showcase.subsections.map(s=>s.id===subId?{...s,entries:[...s.entries,e]}:s)});
    setAddEntryFor(null);setNewEntryGenre("salsa");setNewEntryLabel("");
  }
  function delEntry(subId,entId){
    onUpdate({...showcase,subsections:showcase.subsections.map(s=>s.id===subId?{...s,entries:s.entries.filter(e=>e.id!==entId)}:s)});
  }
  const totalSteps=showcase.subsections.reduce((n,s)=>n+s.entries.reduce((m,e)=>m+e.sequence.length,0),0);

  return (
    <div className="section">
      <div className="sc-detail">
        <div className="sc-detail-header">
          <button className="back-btn" onClick={onBack}>← Volver</button>
          <div className="sc-detail-name">{showcase.name}</div>
        </div>
        <div className="sc-detail-meta">
          {showcase.date && <span className="chip">{new Date(showcase.date+"T12:00:00").toLocaleDateString("es-PE",{day:"numeric",month:"long",year:"numeric"})}</span>}
          <span className="chip">{showcase.subsections.length} subsecciones</span>
          <span className="chip">{totalSteps} pasos en total</span>
        </div>

        {showcase.subsections.length===0 && (
          <div style={{color:"var(--muted)",fontSize:13,padding:"32px 0",textAlign:"center",fontWeight:300}}>Sin subsecciones aún — agrega la primera abajo</div>
        )}

        {showcase.subsections.map(sub=>(
          <div key={sub.id} className="subsection">
            <div className="sub-header">
              <span className="sub-name">{sub.name}</span>
              <div className="sub-line"/>
              <button className="sub-del" onClick={()=>delSub(sub.id)} title="Eliminar">✕</button>
            </div>
            <div className="entries-row">
              {sub.entries.map(entry=>{
                const gi=entryGenreList.find(g=>g.id===entry.genre)||{color:"#888"};
                return(
                  <div key={entry.id} className="entry-card" style={{"--ec":gi.color}}
                    onClick={()=>setSelectedEntry({subId:sub.id,entId:entry.id})}>
                    <div className="entry-card-label">{entry.label}</div>
                    <div className="entry-card-count">{entry.sequence.length} {entry.sequence.length===1?"paso":"pasos"}</div>
                  </div>
                );
              })}
              <button className="add-entry-card" onClick={()=>{setAddEntryFor(sub.id);setNewEntryGenre("salsa");setNewEntryLabel("");}}>
                <span style={{fontSize:16}}>+</span><span>Entrada</span>
              </button>
            </div>
          </div>
        ))}

        <button className="sub-add-btn" onClick={()=>setAddSubModal(true)}>+ Nueva subsección</button>
      </div>

      {addSubModal && (
        <div className="modal-overlay" onClick={()=>setAddSubModal(false)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-header"><span className="modal-title">Nueva subsección</span><button className="modal-close" onClick={()=>setAddSubModal(false)}>✕</button></div>
            <div className="modal-body">
              <div><label className="field-label">Nombre</label>
                <input className="field-input" placeholder="ej. Entrees, Latin Challenge..." value={newSubName}
                  onChange={e=>setNewSubName(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter")addSub();if(e.key==="Escape")setAddSubModal(false);}} autoFocus/>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-cancel" onClick={()=>setAddSubModal(false)}>Cancelar</button>
              <button className="btn-primary" onClick={addSub} disabled={!newSubName.trim()}>Crear</button>
            </div>
          </div>
        </div>
      )}

      {addEntryFor && (
        <div className="modal-overlay" onClick={()=>setAddEntryFor(null)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-header"><span className="modal-title">Agregar entrada</span><button className="modal-close" onClick={()=>setAddEntryFor(null)}>✕</button></div>
            <div className="modal-body">
              <div><label className="field-label">Género / tipo</label>
                <div className="pick-row">
                  {entryGenreList.map(g=>(
                    <button key={g.id} className={`pick-btn ${newEntryGenre===g.id?"sel":""}`}
                      style={{"--pc":g.color}} onClick={()=>setNewEntryGenre(g.id)}>{g.name}</button>
                  ))}
                </div>
              </div>
              <div><label className="field-label">Etiqueta (opcional)</label>
                <input className="field-input" placeholder={entryGenreList.find(g=>g.id===newEntryGenre)?.name||""}
                  value={newEntryLabel} onChange={e=>setNewEntryLabel(e.target.value)}/>
                <p style={{fontSize:12,color:"var(--muted)",marginTop:6,fontWeight:300}}>Si no pones nada usa el nombre del género</p>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-cancel" onClick={()=>setAddEntryFor(null)}>Cancelar</button>
              <button className="btn-primary" onClick={()=>addEntry(addEntryFor)}>Agregar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

