function ShowcasesSection({ genres, onUpdateGenre, showcases, setShowcases }) {
  const [selected,   setSelected]   = useState(null);
  const [showCreate, setShowCreate] = useState(false);
  const [newName,    setNewName]    = useState("");
  const [newDate,    setNewDate]    = useState("");

  function createShowcase(){
    if(!newName.trim())return;
    const sc={id:`sc-${Date.now()}`,name:newName.trim(),date:newDate,subsections:[]};
    setShowcases(prev=>[...prev,sc]);setSelected(sc.id);
    setShowCreate(false);setNewName("");setNewDate("");
  }
  function updateShowcase(updated){setShowcases(prev=>prev.map(s=>s.id===updated.id?updated:s));}

  // fix #2: add custom step to genre repertoire
  function addToRepertoire(genreId, moveName) {
    const genre = genres.find(g=>g.id===genreId);
    if (!genre) return;
    // Don't add if already exists (same name, case-insensitive)
    if (genre.moves.some(m=>m.name.toLowerCase()===moveName.toLowerCase())) return;
    const newMove = {id:`custom-${Date.now()}`,name:moveName,level:"Fundamentos",origin:"custom",learned:true,comfort:"new",youtube:null,custom:true};
    onUpdateGenre({...genre, moves:[...genre.moves, newMove]});
  }

  const current = showcases.find(s=>s.id===selected);
  if (current) {
    return <ShowcaseDetail showcase={current} genres={genres} onUpdate={updateShowcase}
      onAddToRepertoire={addToRepertoire} onBack={()=>setSelected(null)}/>;
  }

  return (
    <div className="section">
      <div className="section-eyebrow">Oricorio</div>
      <h1 className="section-title">Showcases</h1>
      <p className="section-desc">Arma y memoriza las secuencias de tus presentaciones</p>
      {showcases.length===0 ? (
        <div className="sc-empty">
          <div className="sc-empty-icon">🏆</div>
          <div className="sc-empty-title">Sin showcases aún</div>
          <div className="sc-empty-sub">Crea uno para empezar a armar tus secuencias</div>
          <button className="btn-new" onClick={()=>setShowCreate(true)}>+ Nuevo showcase</button>
        </div>
      ):(
        <>
          <div className="sc-grid">
            {showcases.map(sc=>{
              const totalPasos=sc.subsections.reduce((n,s)=>n+s.entries.reduce((m,e)=>m+e.sequence.length,0),0);
              return(
                <div key={sc.id} className="sc-card" onClick={()=>setSelected(sc.id)}>
                  <div className="sc-card-top"><div className="sc-card-name">{sc.name}</div><span className="sc-card-arrow">›</span></div>
                  <div className="sc-card-meta">
                    {sc.date && <span className="chip">{new Date(sc.date+"T12:00:00").toLocaleDateString("es-PE",{month:"short",day:"numeric"})}</span>}
                    <span className="chip">{sc.subsections.length} subsecciones</span>
                    <span className="chip">{totalPasos} pasos</span>
                  </div>
                </div>
              );
            })}
          </div>
          <button className="btn-new" onClick={()=>setShowCreate(true)}>+ Nuevo showcase</button>
        </>
      )}
      {showCreate && (
        <div className="modal-overlay" onClick={()=>setShowCreate(false)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-header"><span className="modal-title">Nuevo showcase</span><button className="modal-close" onClick={()=>setShowCreate(false)}>✕</button></div>
            <div className="modal-body">
              <div><label className="field-label">Nombre</label>
                <input className="field-input" placeholder="ej. AM Peru Showcase Julio 2026" value={newName}
                  onChange={e=>setNewName(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter")createShowcase();if(e.key==="Escape")setShowCreate(false);}} autoFocus/>
              </div>
              <div><label className="field-label">Fecha (opcional)</label>
                <input className="field-input" type="date" value={newDate} onChange={e=>setNewDate(e.target.value)} style={{colorScheme:"dark"}}/>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-cancel" onClick={()=>setShowCreate(false)}>Cancelar</button>
              <button className="btn-primary" onClick={createShowcase} disabled={!newName.trim()}>Crear</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

