// ASISTENTE
// ═══════════════════════════════════════════════════════════════

function buildSystemPrompt(profile, genres, sessions, showcases) {
  const nombre  = profile.nombre || "bailarín";
  const months  = monthsOfDance(profile.ingreso);

  const repertoire = genres.map(g=>{
    const learned = g.moves.filter(m=>m.learned);
    if(!learned.length) return null;
    const list = learned.map(m=>{
      const c = m.comfort==="solid"?"⭐":m.comfort==="progress"?"🔄":"🌱";
      return `${m.name}${c}`;
    }).join(", ");
    return `${g.name}: ${list}`;
  }).filter(Boolean).join("\n");

  const recentSessions = [...sessions]
    .sort((a,b)=>b.date.localeCompare(a.date)).slice(0,6)
    .map(s=>{
      const t  = SESSION_TYPES.find(x=>x.id===s.type);
      const g  = genres.find(x=>x.id===s.genreId);
      const gs = (s.genreIds||[]).map(id=>genres.find(x=>x.id===id)?.name).filter(Boolean);
      const mo = MOODS.find(x=>x.id===s.mood);
      return [
        s.date, t?.label,
        g?.name || gs.join("/"),
        s.level&&(s.level==="pollito"?"nivel pollito":"nivel dragón"),
        mo&&`mood ${mo.emoji}`,
        s.movesLog?.length&&`practicó: ${s.movesLog.join(", ")}`,
        s.notes&&`"${s.notes}"`,
      ].filter(Boolean).join(" · ");
    }).join("\n") || "Sin sesiones aún";

  const showcaseCtx = showcases.map(sc=>{
    const subs = sc.subsections.map(sub=>{
      const entries = sub.entries.map(e=>`${e.label}(${e.sequence.length}p)`).join(", ");
      return `${sub.name}: ${entries}`;
    }).join(" | ");
    return `${sc.name} — ${subs}`;
  }).join("\n");

  return `Eres Oricorio, el asistente personal de baile de ${nombre}.

PERFIL:
- ${months!=null?`Lleva ${months} meses bailando`:"Estudiante de baile"} en Arthur Murray Perú
${profile.profesor?`- Profesor: ${profile.profesor}`:""}
${profile.academiaSecundaria?`- También va a ${profile.academiaSecundaria}`:""}
${profile.notas?`- Objetivos: ${profile.notas}`:""}

REPERTORIO ACTUAL:
${repertoire||"Sin moves aprendidos aún"}
(🌱=recién visto, 🔄=en progreso, ⭐=consolidado)

SESIONES RECIENTES:
${recentSessions}

${showcases.length?`SHOWCASES:\n${showcaseCtx}`:""}

ESTILO DE RESPUESTA:
- Cálido, motivador, con humor peruano sutil — como un profe que también es pata
- Mezclas español con términos de baile en inglés cuando es natural
- Tips concretos y simples, no teoría larga
- Empatizas antes de dar soluciones cuando hay frustraciones
- Respuestas conversacionales, no en listas largas
- Máximo 1-2 emojis por mensaje
- Una sola pregunta a la vez si preguntas
- Español peruano: "sientes", "tienes", "puedes" — nunca voseo argentino`;
}

function AsistenteSection({ profile, genres, sessions, showcases }) {
  const [messages, setMessages] = useState([]);
  const [input,    setInput]    = useState("");
  const [loading,  setLoading]  = useState(false);
  const [chatLoaded, setChatLoaded] = useState(false);
  const messagesEndRef = { current: null };

  // Load history
  useEffect(()=>{
    loadChat().then(d=>{
      if(d&&d.length) setMessages(d);
      else setMessages([{
        role:"assistant",
        content:`¡Hola${profile.nombre?" "+profile.nombre:""}! 👋 Soy Oricorio, tu asistente de baile. Tengo acceso a tu repertorio, tus clases y tus showcases — pregúntame lo que quieras.\n\n¿Cómo van las clases últimamente?`,
        time: new Date().toLocaleTimeString("es-PE",{hour:"2-digit",minute:"2-digit"})
      }]);
      setChatLoaded(true);
    });
  },[]);

  // Save history (keep last 30)
  useEffect(()=>{
    if(chatLoaded && messages.length) saveChat(messages.slice(-30));
  },[messages, chatLoaded]);

  // Auto-scroll
  useEffect(()=>{
    const el = document.querySelector(".chat-messages");
    if(el) el.scrollTop = el.scrollHeight;
  },[messages, loading]);

  async function sendMessage() {
    const text = input.trim();
    if(!text||loading) return;
    const time = new Date().toLocaleTimeString("es-PE",{hour:"2-digit",minute:"2-digit"});
    const userMsg = {role:"user",content:text,time};
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);

    try {
      const apiMessages = newMessages.map(m=>({role:m.role,content:m.content}));
      const res = await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:1000,
          system: buildSystemPrompt(profile,genres,sessions,showcases),
          messages: apiMessages,
        }),
      });
      const data = await res.json();
      const reply = data.content?.map(c=>c.text||"").join("") || "Hmm, algo falló 😅 Prueba de nuevo.";
      setMessages(prev=>[...prev,{
        role:"assistant",content:reply,
        time:new Date().toLocaleTimeString("es-PE",{hour:"2-digit",minute:"2-digit"})
      }]);
    } catch {
      setMessages(prev=>[...prev,{role:"assistant",content:"Perdí el ritmo un segundo 😅 ¿Puedes repetir?",time:""}]);
    } finally {
      setLoading(false);
    }
  }

  function handleKey(e){if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();sendMessage();}}

  function clearChat(){
    const welcome = {
      role:"assistant",
      content:`Chat reiniciado. ¿En qué te puedo ayudar${profile.nombre?" "+profile.nombre:""}?`,
      time:new Date().toLocaleTimeString("es-PE",{hour:"2-digit",minute:"2-digit"})
    };
    setMessages([welcome]);
  }

  return (
    <div className="chat-section">
      <div className="chat-header-bar">
        <div className="chat-header-info">
          <div className="chat-avatar"><img src={ORICORIO_IMG} alt="Oricorio" style={{width:"100%",height:"100%",objectFit:"contain",padding:2}}/></div>
          <div>
            <div className="chat-header-name">Oricorio</div>
            <div className="chat-header-status">● Tu asistente de baile</div>
          </div>
        </div>
        <button className="chat-clear-btn" onClick={clearChat}>Limpiar chat</button>
      </div>

      <div className="chat-messages">
        {messages.map((m,i)=>(
          <div key={i} className={`chat-msg ${m.role}`}>
            <div className="chat-bubble">{m.content}</div>
            {m.time && <div className="chat-time">{m.time}</div>}
          </div>
        ))}
        {loading && (
          <div className="chat-msg assistant">
            <div className="typing-indicator">
              <div className="typing-dot"/><div className="typing-dot"/><div className="typing-dot"/>
            </div>
          </div>
        )}
      </div>

      <div className="chat-input-row">
        <textarea className="chat-input" rows={1}
          placeholder="Pregunta sobre tu repertorio, pide tips, prepara el showcase..."
          value={input} onChange={e=>setInput(e.target.value)} onKeyDown={handleKey}/>
        <button className="chat-send-btn" onClick={sendMessage} disabled={loading||!input.trim()}>↑</button>
      </div>
    </div>
  );
}

